using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

/// <summary>
/// EF-backed implementation used during interactive server rendering.
/// </summary>
public class ShipmentServerService(IDbContextFactory<ApplicationDbContext> contextFactory) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        await using var db = await contextFactory.CreateDbContextAsync();
        return await db.Shipments.OrderByDescending(s => s.CreatedDate)
            .Select(s => ToDto(s)).ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        await using var db = await contextFactory.CreateDbContextAsync();
        var s = await db.Shipments.FirstOrDefaultAsync(x => x.TrackingNumber == trackingNumber);
        return s is null ? null : ToDto(s);
    }

    public async Task<List<ShipmentDto>> GetShipmentsByCustomerAsync(string email)
    {
        await using var db = await contextFactory.CreateDbContextAsync();
        return await db.Shipments.Where(s => s.CustomerEmail == email)
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => ToDto(s)).ToListAsync();
    }

