using System.Security.Claims;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedDate)
                .ToListAsync();
            return Results.Ok(shipments.Select(ToDto));
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var s = await db.Shipments.FirstOrDefaultAsync(x => x.TrackingNumber == trackingNumber);
            return s is null ? Results.NotFound() : Results.Ok(ToDto(s));
        });

        group.MapGet("/customer/{email}", async (string email, ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .OrderByDescending(s => s.CreatedDate)
                .ToListAsync();
            return Results.Ok(shipments.Select(ToDto));
        });

        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var entity = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = Data.ShipmentStatus.Pending,
                CreatedDate = DateTime.UtcNow,
                EstimatedDelivery = dto.EstimatedDelivery,
                RecipientName = dto.RecipientName,
                Description = dto.Description,
                CustomerEmail = dto.CustomerEmail
            };
            db.Shipments.Add(entity);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/track/{entity.TrackingNumber}", ToDto(entity));
        });

        group.MapPut("/{id}/status", async (int id, StatusUpdateRequest request, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FindAsync(id);
            if (entity is null) return Results.NotFound();

            entity.Status = (Data.ShipmentStatus)(int)request.Status;
            if (request.Status == ShipmentStatus.Delivered)
                entity.ActualDelivery = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(ToDto(entity));
        });
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)(int)s.Status,
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        Description = s.Description,
        CustomerEmail = s.CustomerEmail
    };

    private record StatusUpdateRequest(ShipmentStatus Status);
}

