@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2 class="mb-4">📦 Shipment Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="filterStatus">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">
            ➕ New Shipment
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="createShipment">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-4">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Recipient</label>
                        <InputText class="form-control" @bind-Value="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Customer Email</label>
                        <InputText class="form-control" @bind-Value="newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="newShipment.Description" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Est. Delivery</label>
                        <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                    </div>
                </div>
                <div class="mt-3">
                    <button type="submit" class="btn btn-success me-2" disabled="@isCreating">
                        @(isCreating ? "Creating..." : "Create")
                    </button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
                <ValidationSummary class="mt-2" />
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p class="text-muted">No shipments match your filter.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><strong>@s.TrackingNumber</strong></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Cancelled)
                            {
                                <select class="form-select form-select-sm d-inline-block w-auto"
                                        @onchange="(e) => UpdateStatus(s.Id, e)">
                                    <option value="">Change...</option>
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        @if (status != s.Status)
                                        {
                                            <option value="@((int)status)">@status</option>
                                        }
                                    }
                                </select>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string filterStatus = "";
    private bool showCreateForm;
    private bool isCreating;
    private ShipmentDto newShipment = new();

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(filterStatus) || s.Status.ToString() == filterStatus));

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        newShipment = new ShipmentDto
        {
            TrackingNumber = $"TRK-{Random.Shared.Next(100000, 999999)}",
            EstimatedDelivery = DateTime.UtcNow.AddDays(5)
        };
        showCreateForm = true;
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        showCreateForm = false;
        isCreating = false;
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusInt))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(id, (ShipmentStatus)statusInt);
            if (updated is not null && shipments is not null)
            {
                var index = shipments.FindIndex(s => s.Id == id);
                if (index >= 0) shipments[index] = updated;
            }
        }
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Components.Authorization
@inject IShipmentService ShipmentService
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>Track Shipment</PageTitle>

<h2 class="mb-4">🔍 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. TRK-001001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isSearching">
                @(isSearching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (searchPerformed && trackedShipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>.
    </div>
}

@if (trackedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header bg-primary text-white">
            <h5 class="mb-0">Shipment @trackedShipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl class="row">
                        <dt class="col-sm-5">Status</dt>
                        <dd class="col-sm-7">
                            <span class="badge @StatusBadgeClass(trackedShipment.Status) fs-6">
                                @trackedShipment.Status
                            </span>
                        </dd>
                        <dt class="col-sm-5">Origin</dt>
                        <dd class="col-sm-7">@trackedShipment.Origin</dd>
                        <dt class="col-sm-5">Destination</dt>
                        <dd class="col-sm-7">@trackedShipment.Destination</dd>
                        <dt class="col-sm-5">Recipient</dt>
                        <dd class="col-sm-7">@trackedShipment.RecipientName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl class="row">
                        <dt class="col-sm-5">Shipped Date</dt>
                        <dd class="col-sm-7">@trackedShipment.CreatedDate.ToString("MMM dd, yyyy")</dd>
                        <dt class="col-sm-5">Est. Delivery</dt>
                        <dd class="col-sm-7">
                            @if (trackedShipment.EstimatedDelivery.HasValue)
                            {
                                <strong>@trackedShipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</strong>
                            }
                            else
                            {
                                <span class="text-muted">TBD</span>
                            }
                        </dd>
                        @if (trackedShipment.ActualDelivery.HasValue)
                        {
                            <dt class="col-sm-5">Delivered On</dt>
                            <dd class="col-sm-7 text-success">
                                <strong>@trackedShipment.ActualDelivery.Value.ToString("MMM dd, yyyy HH:mm")</strong>
                            </dd>
                        }
                        <dt class="col-sm-5">Description</dt>
                        <dd class="col-sm-7">@trackedShipment.Description</dd>
                    </dl>
                </div>
            </div>

            <!-- Progress visualization -->
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @ProgressBarClass(trackedShipment.Status)"
                         role="progressbar" style="width: @ProgressPercent(trackedShipment.Status)%"
                         aria-valuenow="@ProgressPercent(trackedShipment.Status)" aria-valuemin="0" aria-valuemax="100">
                        @trackedShipment.Status
                    </div>
                </div>
                <div class="d-flex justify-content-between mt-1 small text-muted">
                    <span>Pending</span>
                    <span>Picked Up</span>
                    <span>In Transit</span>
                    <span>Out for Delivery</span>
                    <span>Delivered</span>
                </div>
            </div>
        </div>
    </div>
}

<AuthorizeView>
    <Authorized>
        <h4 class="mt-5 mb-3">📋 My Shipments</h4>
        @if (myShipments is null)
        {
            <p><em>Loading your shipments...</em></p>
        }
        else if (!myShipments.Any())
        {
            <p class="text-muted">No shipments found for your account.</p>
        }
        else
        {
            <div class="table-responsive">
                <table class="table table-striped">
                    <thead>
                        <tr>
                            <th>Tracking #</th>
                            <th>Destination</th>
                            <th>Status</th>
                            <th>Est. Delivery</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var s in myShipments)
                        {
                            <tr>
                                <td><strong>@s.TrackingNumber</strong></td>
                                <td>@s.Destination</td>
                                <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                                <td>@s.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                                <td>
                                    <button class="btn btn-sm btn-outline-primary"
                                            @onclick="() => QuickTrack(s.TrackingNumber)">
                                        Details
                                    </button>
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
    </Authorized>
</AuthorizeView>

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private bool isSearching;
    private bool searchPerformed;
    private ShipmentDto? trackedShipment;
    private List<ShipmentDto>? myShipments;

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthStateProvider.GetAuthenticationStateAsync();
        var email = authState.User.Identity?.Name;
        if (!string.IsNullOrEmpty(email))
        {
            myShipments = await ShipmentService.GetShipmentsByCustomerAsync(email);
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();
        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searchPerformed = true;
        isSearching = false;
    }

    private async Task QuickTrack(string number)
    {
        trackingNumber = number;
        await TrackShipment();
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string ProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };

    private static int ProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}

