@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2 class="mb-4">📦 Shipment Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="filterStatus">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">
            ➕ New Shipment
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="createShipment">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-4">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Recipient</label>
                        <InputText class="form-control" @bind-Value="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Customer Email</label>
                        <InputText class="form-control" @bind-Value="newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="newShipment.Description" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Est. Delivery</label>
                        <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                    </div>
                </div>
                <div class="mt-3">
                    <button type="submit" class="btn btn-success me-2" disabled="@isCreating">
                        @(isCreating ? "Creating..." : "Create")
                    </button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
                <ValidationSummary class="mt-2" />
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p class="text-muted">No shipments match your filter.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><strong>@s.TrackingNumber</strong></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Cancelled)
                            {
                                <select class="form-select form-select-sm d-inline-block w-auto"
                                        @onchange="(e) => UpdateStatus(s.Id, e)">
                                    <option value="">Change...</option>
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        @if (status != s.Status)
                                        {
                                            <option value="@((int)status)">@status</option>
                                        }
                                    }
                                </select>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string filterStatus = "";
    private bool showCreateForm;
    private bool isCreating;
    private ShipmentDto newShipment = new();

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(filterStatus) || s.Status.ToString() == filterStatus));

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        newShipment = new ShipmentDto
        {
            TrackingNumber = $"TRK-{Random.Shared.Next(100000, 999999)}",
            EstimatedDelivery = DateTime.UtcNow.AddDays(5)
        };
        showCreateForm = true;
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        showCreateForm = false;
        isCreating = false;
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusInt))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(id, (ShipmentStatus)statusInt);
            if (updated is not null && shipments is not null)
            {
                var index = shipments.FindIndex(s => s.Id == id);
                if (index >= 0) shipments[index] = updated;
            }
        }
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

