                        <dt class="col-sm-5">Est. Delivery</dt>
                        <dd class="col-sm-7">
                            @if (trackedShipment.EstimatedDelivery.HasValue)
                            {
                                <strong>@trackedShipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</strong>
                            }
                            else
                            {
                                <span class="text-muted">TBD</span>
                            }
                        </dd>
                        @if (trackedShipment.ActualDelivery.HasValue)
