            <!-- Progress visualization -->
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @ProgressBarClass(trackedShipment.Status)"
                         role="progressbar" style="width: @ProgressPercent(trackedShipment.Status)%"
                         aria-valuenow="@ProgressPercent(trackedShipment.Status)" aria-valuemin="0" aria-valuemax="100">
                        @trackedShipment.Status
                    </div>
                </div>
                <div class="d-flex justify-content-between mt-1 small text-muted">
                    <span>Pending</span>
                    <span>Picked Up</span>
                    <span>In Transit</span>
                    <span>Out for Delivery</span>
                    <span>Delivered</span>
                </div>
            </div>
        </div>
    </div>
}

