using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

/// <summary>
/// EF-backed implementation used during interactive server rendering.
/// </summary>
public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments.OrderByDescending(s => s.CreatedDate)
            .Select(s => ToDto(s)).ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var s = await db.Shipments.FirstOrDefaultAsync(x => x.TrackingNumber == trackingNumber);
        return s is null ? null : ToDto(s);
    }

    public async Task<List<ShipmentDto>> GetShipmentsByCustomerAsync(string email)
    {
        return await db.Shipments.Where(s => s.CustomerEmail == email)
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => ToDto(s)).ToListAsync();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var entity = new Shipment
        {
            TrackingNumber = dto.TrackingNumber,
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = Data.ShipmentStatus.Pending,
            CreatedDate = DateTime.UtcNow,
            EstimatedDelivery = dto.EstimatedDelivery,
            RecipientName = dto.RecipientName,
            Description = dto.Description,
            CustomerEmail = dto.CustomerEmail
        };
        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return ToDto(entity);
    }

    public async Task<ShipmentDto?> UpdateShipmentStatusAsync(int id, Client.Models.ShipmentStatus newStatus)
    {
        var entity = await db.Shipments.FindAsync(id);
        if (entity is null) return null;

        entity.Status = (Data.ShipmentStatus)(int)newStatus;
        if (newStatus == Client.Models.ShipmentStatus.Delivered)
            entity.ActualDelivery = DateTime.UtcNow;

        await db.SaveChangesAsync();
        return ToDto(entity);
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (Client.Models.ShipmentStatus)(int)s.Status,
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        Description = s.Description,
        CustomerEmail = s.CustomerEmail
    };
}

